import React, { useEffect, useState } from "react";
import { Form, Col, Button } from "react-bootstrap";
import { Link, useParams } from "react-router-dom";
import { readDeck } from "../../utils/api/index.js";

function AddCard() {
  const [deck, setDeck] = useState();
  const params = useParams();

  // Create a new id for the new deck.
  useEffect(() => {
    async function loadDeck() {
      const deckData = await readDeck(params.deckId);
      setDeck(deckData);
    }
    loadDeck();
  }, []);

  // Creates a new deck with the information that was inputed.
  async function handleAddCardBtn() {}

  if (!deck) return <p>Loading...</p>;
  return (
    <div>
      <Form>
        <Col>
          <h1>{deck.name}: Add Card</h1>
          <Form.Label className="mt-1">Front</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder="Frontside of card"
            type="text"
            id="deckTitleInput"
          ></Form.Control>
          <Form.Label className="mt-1">Back</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder="Backside of card"
            as="textarea"
            id="deckTextInput"
          ></Form.Control>
          <Link to={`/decks/${deck.id}`}>
            <Button className="mt-2 mr-1" variant="secondary">
              Done
            </Button>
          </Link>
          <Button onClick={() => handleAddCardBtn} className="mt-2 mr-1">
            Save
          </Button>
        </Col>
      </Form>
    </div>
  );
}

export default AddCard;
